steps.command:
SELECT pg_size_pretty(pg_total_relation_size('bookings.ticket_flights')) AS total_size,
       pg_size_pretty(pg_table_size('bookings.ticket_flights')) AS table_size,
       pg_size_pretty(pg_indexes_size('bookings.ticket_flights')) AS indexes_size;

EXPLAIN ANALYZE
SELECT * FROM bookings.flights
WHERE flight_no = 'AA123' AND scheduled_departure = '2024-01-01 00:00:00';

SELECT table_name, privilege_type
FROM information_schema.role_table_grants
WHERE grantee = 'app_user' AND table_name = 'ticket_flights';

SELECT table_schema, table_name, privilege_type
FROM information_schema.role_table_grants
WHERE grantee = 'app_user' AND table_name LIKE '%ticket%';

DROP INDEX bookings.idx_tf_junk1;
DROP INDEX bookings.idx_tf_junk2;
DROP INDEX bookings.idx_tf_junk3;

SELECT indexname, pg_size_pretty(pg_relation_size(indexname::regclass)) AS size
FROM pg_indexes
WHERE tablename IN ('ticket_flights', 'flights') AND schemaname = 'bookings';

