steps.command:
SELECT
    pg_size_pretty(pg_total_relation_size('bookings.bookings')) AS bookings_size,
    pg_size_pretty(pg_total_relation_size('bookings.bookings_pkey')) AS bookings_pkey_size;

SELECT indexname, indexdef
FROM pg_indexes
WHERE tablename = 'ticket_flights';

SELECT relname, n_dead_tup, n_live_tup, last_autovacuum, last_autoanalyze
FROM pg_stat_all_tables
WHERE schemaname = 'bookings' AND n_dead_tup > 0;

SELECT pg_terminate_backend(pid)
FROM pg_stat_activity
WHERE state = 'idle in transaction';
